import{_ as a,o as i,i as l,aZ as t}from"./chunks/framework.D08fXB_e.js";const m=JSON.parse('{"title":"oc-theme-customizer","description":"","frontmatter":{},"headers":[],"relativePath":"guide/skills/oc-theme-customizer.md","filePath":"guide/skills/oc-theme-customizer.md"}'),s={name:"guide/skills/oc-theme-customizer.md"};function o(c,e,d,n,r,p){return i(),l("div",null,[...e[0]||(e[0]=[t(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /guide/skills/oc-theme-customizer.md for this page in Markdown format</div><h1 id="oc-theme-customizer" tabindex="-1">oc-theme-customizer <a class="header-anchor" href="#oc-theme-customizer" aria-label="Permalink to “oc-theme-customizer”">​</a></h1><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to “适用场景”">​</a></h2><ul><li>需要一套新的品牌主题</li><li>需要新增或调整基础色</li><li>想做科技感、莫兰迪、北欧极简、赛博朋克、吉卜力等风格主题</li><li>想把设计稿、品牌色或 tweakcn 配色转换成框架主题</li><li>想让亮色和暗色模式使用不同的基础色或主题色</li></ul><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to “使用方式”">​</a></h2><p>直接说明以下信息即可：</p><ul><li>想要的风格</li><li>品牌主色或参考色</li><li>是否需要调整基础色基调</li><li>是否需要在某个应用中启用</li><li>目标应用，例如 <code>example</code></li></ul><p>示例：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我做一套新的框架主题。</span></span>
<span class="line"><span>风格偏科技感，品牌主色是 #2563EB。</span></span>
<span class="line"><span>基础色想要冷灰一点，暗色模式更沉稳。</span></span>
<span class="line"><span>请同时生成基础色和主题色，并在 example 应用中启用。</span></span></code></pre></div><h2 id="结果" tabindex="-1">结果 <a class="header-anchor" href="#结果" aria-label="Permalink to “结果”">​</a></h2><p>通常会：</p><ul><li>修改 <code>packages/themes/index.ts</code></li><li>修改 <code>apps/&lt;app&gt;/src/settings.ts</code>，启用该主题</li></ul><p>主题按 <code>packages/themes/index.ts</code> 当前的 3 层结构分别处理：</p><ul><li><code>BASE_COLORS</code>：基础色（完整 shadcn token 集合）</li><li><code>THEMES</code>：主题色（通常只覆盖 <code>--primary</code> / <code>--secondary</code> 等）</li><li>必要时调整 <code>FRAMEWORK_COLORS</code>：框架区域（顶部、侧边栏、标签栏、主内容区）配色</li><li><code>theme.baseColorLight / baseColorDark</code></li><li><code>theme.light / dark</code></li></ul><blockquote><p>始终同时生成 light 和 dark 两套配置，色值使用 OKLCH（<code>L C H</code> 三个数值，不含 <code>oklch()</code> 包裹）。</p></blockquote>`,15)])])}const u=a(s,[["render",o]]);export{m as __pageData,u as default};
